11	actor DeviceTransmition {
12	    
13	    @LazyInjected(\.analyticsEngine) private var analyticsEngine
14	
15	    enum DeviceTransmitionError: Error {
16	        case peripheral
17	    }
18	    
19	    private var taskQueue = TaskQueue()
20	    private weak var peripheral: Peripheral?
21	    
22	    init(peripheral: Peripheral?) {
23	        self.peripheral = peripheral
24	    }
25	    
26	    func stop() {
27	        peripheral?.cancel()
28	        taskQueue.close()
29	    }
30	    
31	    func send<T: BluetoothCommand>(command: T) async -> Result<T.Response, Error> {
32	        guard let peripheral else {
33	            return .failure(DeviceTransmitionError.peripheral)
34	        }
35	        do {
36	            let response: T.Response = try await taskQueue.dispatch {
37	                let storage = try await peripheral.write(command: command)
38	                return try command.response.decode(storage)
39	            }
40	            return .success(response)
41	        } catch {
42	            Log.error("Command: \(type(of: command))\n   Error: \(error)")
43	            if let parseError = error as? CommandError {
44	                self.analyticsEngine.reportError(
45	                    BluetoothCommandParseError(
46	                        storage: parseError.storage,
47	                        identifier: command.identifier,
48	                        underlyingError: parseError.error
49	                    )
50	                )
51	            }
52	            return .failure(error)
53	        }
54	    }
55	}
